import React, { useCallback, useState } from 'react';
import { useDropzone } from 'react-dropzone';
import {
  Box,
  Typography,
  LinearProgress,
  Alert,
  Paper,
} from '@mui/material';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';

function FileUploader({ onUploadSuccess, allowedTypes }) {
  const [uploadProgress, setUploadProgress] = useState(0);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [selectedFile, setSelectedFile] = useState(null);
  const [fileName, setFileName] = useState('');
  const [uploading, setUploading] = useState(false);

  // Function to create appropriate mock data based on file name/type
  const createMockData = (file) => {
    const isCsv = file.name.toLowerCase().endsWith('.csv');
    const isJson = file.name.toLowerCase().endsWith('.json');

    let columns = [];
    let preview = [];

    // Create data based on filename
    if (file.name.toLowerCase().includes('sales')) {
      columns = ['id', 'date', 'product', 'category', 'price', 'quantity'];
      preview = [
        { id: 1, date: '2023-01-01', product: 'Product A', category: 'Electronics', price: 299.99, quantity: 5 },
        { id: 2, date: '2023-01-02', product: 'Product B', category: 'Clothing', price: 59.99, quantity: 12 },
        { id: 3, date: '2023-01-03', product: 'Product C', category: 'Home', price: 149.99, quantity: 8 }
      ];
    } else if (file.name.toLowerCase().includes('customer')) {
      columns = ['id', 'name', 'email', 'age', 'country', 'registered_date'];
      preview = [
        { id: 1, name: 'John Smith', email: 'john@example.com', age: 32, country: 'USA', registered_date: '2022-12-15' },
        { id: 2, name: 'Jane Doe', email: 'jane@example.com', age: 28, country: 'Canada', registered_date: '2022-12-18' },
        { id: 3, name: 'Alice Johnson', email: 'alice@example.com', age: 45, country: 'UK', registered_date: '2022-12-20' }
      ];
    } else if (file.name.toLowerCase().includes('stock') || file.name.toLowerCase().includes('market')) {
      columns = ['symbol', 'date', 'open', 'high', 'low', 'close', 'volume'];
      preview = [
        { symbol: 'AAPL', date: '2023-01-01', open: 142.5, high: 144.3, low: 141.2, close: 143.8, volume: 12345678 },
        { symbol: 'MSFT', date: '2023-01-01', open: 336.2, high: 339.8, low: 335.1, close: 337.5, volume: 9876543 },
        { symbol: 'GOOGL', date: '2023-01-01', open: 128.7, high: 130.2, low: 127.9, close: 129.5, volume: 8765432 }
      ];
    } else {
      // Generic data for any other file
      columns = ['id', 'name', 'value', 'date', 'category'];
      preview = [
        { id: 1, name: 'Item 1', value: 42, date: '2023-01-01', category: 'Category A' },
        { id: 2, name: 'Item 2', value: 73, date: '2023-01-02', category: 'Category B' },
        { id: 3, name: 'Item 3', value: 29, date: '2023-01-03', category: 'Category A' }
      ];
    }

    return {
      columns,
      preview
    };
  };

  const uploadFile = async (file) => {
    if (!file) return;

    setUploading(true);
    setError(null);
    setSuccess(false);
    setUploadProgress(0);

    // Simulate upload progress for better UX
    const progressInterval = setInterval(() => {
      setUploadProgress((prevProgress) => {
        const newProgress = Math.min(prevProgress + 5, 90);
        return newProgress;
      });
    }, 100);

    try {
      const formData = new FormData();
      formData.append('file', file);

      console.log('Uploading file:', {
        name: file.name,
        type: file.type,
        size: file.size
      });

      const response = await fetch('/api/files/upload', {
        method: 'POST',
        body: formData
      });

      clearInterval(progressInterval);

      console.log('Upload response status:', response.status);

      if (!response.ok) {
        let errorMessage = `Upload failed with status ${response.status}`;
        try {
          const errorText = await response.text();
          try {
            const errorData = JSON.parse(errorText);
            errorMessage = errorData.error || errorMessage;
          } catch (parseError) {
            // If we can't parse JSON, use the raw text
            if (errorText) errorMessage = errorText;
          }
        } catch (e) {
          console.error('Could not parse error response:', e);
        }
        throw new Error(errorMessage);
      }

      const data = await response.json();
      console.log('Upload successful:', data);

      setUploadProgress(100);
      setSuccess(true);

      // Wait a moment to show success message before closing
      setTimeout(() => {
        setSelectedFile(null);
        setFileName('');

        // Call the success callback with the file data
        if (onUploadSuccess) {
          onUploadSuccess(file);
        }
      }, 1500);
    } catch (error) {
      console.error('Upload error:', error);
      setError(error.message || 'Failed to upload file');
      setUploadProgress(0);
    } finally {
      clearInterval(progressInterval);
      setUploading(false);
    }
  };

  const onDrop = useCallback((acceptedFiles) => {
    const file = acceptedFiles[0]; // Handle one file at a time

    if (!file) return;

    console.log('File dropped:', file.name, file.type);

    const csvType = file.type === 'text/csv' || 
                    file.name.toLowerCase().endsWith('.csv');

    const jsonType = file.type === 'application/json' || 
                     file.name.toLowerCase().endsWith('.json');

    if (!csvType && !jsonType) {
      setError(`File type not supported. Please upload CSV or JSON files.`);
      return;
    }

    setSelectedFile(file);
    setFileName(file.name);

    // Upload the file immediately when dropped
    uploadFile(file);
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'text/csv': ['.csv'],
      'application/json': ['.json']
    },
    multiple: false,
  });

  return (
    <Box sx={{ width: '100%' }}>
      {error && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}

      {success && (
        <Alert severity="success" sx={{ mb: 2 }}>
          File uploaded successfully!
        </Alert>
      )}

      <Paper
        {...getRootProps()}
        sx={{
          p: 3,
          border: '2px dashed',
          borderColor: isDragActive ? 'primary.main' : 'grey.300',
          backgroundColor: isDragActive ? 'action.hover' : 'background.paper',
          cursor: uploading ? 'default' : 'pointer',
          transition: 'all 0.2s ease',
          '&:hover': {
            borderColor: uploading ? 'grey.300' : 'primary.main',
            backgroundColor: uploading ? 'background.paper' : 'action.hover',
          },
        }}
      >
        <input {...getInputProps()} disabled={uploading} />
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            textAlign: 'center',
          }}
        >
          <CloudUploadIcon
            sx={{ fontSize: 48, color: 'primary.main', mb: 2 }}
          />
          <Typography variant="h6" gutterBottom>
            {isDragActive
              ? 'Drop the file here'
              : uploading
              ? 'Uploading...'
              : 'Drag and drop a file here, or click to select'}
          </Typography>
          <Typography variant="body2" color="text.secondary">
            Supported formats: CSV, JSON, and text files
          </Typography>
        </Box>
      </Paper>

      {uploadProgress > 0 && (
        <Box sx={{ mt: 2 }}>
          <LinearProgress variant="determinate" value={uploadProgress} />
          <Typography variant="body2" color="text.secondary" align="center" sx={{ mt: 1 }}>
            {uploadProgress < 100 ? `${uploadProgress}% uploaded` : 'Upload complete!'}
          </Typography>
        </Box>
      )}
    </Box>
  );
}

export default FileUploader;
